import datetime

# Load cases from the query
with open('var_functions.query_db:26', 'r') as f:
    cases = json.load(f)

# Load accounts from the query
with open('var_functions.query_db:20', 'r') as f:
    accounts = json.load(f)

# Create account ID to state mapping
account_states = {}
for acc in accounts:
    acc_id = acc['Id']
    state = acc['ShippingState']
    # Store with and without # for flexibility
    account_states[acc_id] = state
    if acc_id.startswith('#'):
        account_states[acc_id[1:]] = state
    else:
        account_states['#' + acc_id] = state

# Process cases
state_closure_times = {}
total_cases = 0

for case in cases:
    try:
        # Skip cases with invalid or empty account ID
        acc_id = case['accountid'].strip() if case['accountid'] else None
        if not acc_id:
            continue

        # Get state
        state = account_states.get(acc_id)
        if not state:
            continue

        # Calculate closure time in hours
        created = datetime.datetime.fromisoformat(case['createddate'].replace('Z', '+00:00'))
        closed = datetime.datetime.fromisoformat(case['closeddate'].replace('Z', '+00:00'))
        closure_hours = (closed - created).total_seconds() / 3600

        # Add to state's list
        if state not in state_closure_times:
            state_closure_times[state] = []
        state_closure_times[state].append(closure_hours)
        total_cases += 1

    except Exception as e:
        continue

# Calculate average closure time per state
state_averages = {}
for state, times in state_closure_times.items():
    state_averages[state] = sum(times) / len(times)

# Find state with quickest closure time
if not state_averages:
    result = {'top_state': None}
else:
    sorted_states = sorted(state_averages.items(), key=lambda x: x[1])
    top_state = sorted_states[0][0]
    result = {'top_state': top_state}

print('__RESULT__:')
print(json.dumps(result))"}

